import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import "./Login.css";

export default function Login() {
  const navigate = useNavigate();
  const [role, setRole] = useState("");

  const handleLogin = (e) => {
    e.preventDefault();

    const password = e.target.password.value.trim();
    const selectedRole = e.target.role.value;
    const enteredRoll = e.target.rollno?.value?.trim();
    const enteredEmail = e.target.email?.value?.trim();

    const users = JSON.parse(localStorage.getItem("users")) || [];

    // Find matching user
    const matchedUser = users.find((user) => {
      if (user.role !== selectedRole || user.password !== password) return false;

      if (selectedRole === "student") {
        return user.roll === enteredRoll;
      } else {
        return user.email === enteredEmail;
      }
    });

    if (matchedUser) {
      localStorage.setItem("currentUser", JSON.stringify(matchedUser));
      alert(`Login successful as ${selectedRole}`);
      navigate("/dashboard");
    } else {
      alert("Invalid credentials or role!");
    }
  };

  return (
    <div className="split-layout">
      <div className="left-panel">
        <h1>🎓 Campus Connect</h1>
        <img
          src="https://img.freepik.com/premium-vector/graduation-students_1214-321.jpg"
          alt="Graduates"
          className="illustration"
        />
      </div>

      <div className="right-panel">
        <div className="form-box shadow-card">
          <div className="tabs">
            <Link to="/login" className="tab active">Login</Link>
            <Link to="/register" className="tab">Signup</Link>
          </div>

          <form onSubmit={handleLogin}>
            <label>Role</label>
            <select name="role" required value={role} onChange={(e) => setRole(e.target.value)}>
              <option value="">-- Select Role --</option>
              <option value="student">Student</option>
              <option value="admin">Admin</option>
              <option value="hr">HR</option>
            </select>

            {role === "student" && (
              <>
                <label>University Roll Number</label>
                <input name="rollno" placeholder="Enter your university roll number" required />
              </>
            )}

            {role !== "student" && role !== "" && (
              <>
                <label>Email</label>
                <input name="email" type="email" placeholder="Enter your email" required />
              </>
            )}

            <label>Password</label>
            <input name="password" type="password" placeholder="Enter password" required />

            <button type="submit">Login</button>
          </form>

          <p className="signup-cta">
            New to Campus Connect? <Link to="/register"><strong>Signup</strong></Link>
          </p>
        </div>
      </div>
    </div>
  );
}
